        const uint32_t lenElems = rows * innerLen_;
        AscendC::LocalTensor<float> yLocal = bufQueue_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, lenElems);
        bufQueue_.FreeTensor(yLocal);
    }

